function parseJson(value, fallback) {
  if (value === null || value === undefined) return fallback;
  if (typeof value === "object") return value;
  if (typeof value === "string") {
    try {
      return JSON.parse(value);
    } catch (e) {
      return fallback;
    }
  }
  return fallback;
}

function safeString(value, fallback = null) {
  if (value === null || value === undefined) return fallback;
  const str = String(value).trim();
  return str.length ? str : fallback;
}

function safeNumber(value, fallback = null) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function cleanArray(values) {
  if (!Array.isArray(values)) return [];

  const result = [];

  for (const value of values) {
    if (typeof value === "string" && value.trim() !== "") {
      result.push(value.trim());
    }
  }

  return [...new Set(result)];
}

function unique(values) {
  return [...new Set((values || []).filter(Boolean))];
}

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== "") return value;
  }
  return null;
}

function compactObject(obj) {
  return Object.fromEntries(
    Object.entries(obj || {}).filter(([_, value]) => value !== undefined)
  );
}

const raw = $json || {};

let triggerRaw = {};
try {
  triggerRaw = $("rules_engine").first().json || {};
} catch (e) {
  triggerRaw = {};
}

const source =
  raw.event || raw.lead || raw.lead_state || raw.context_packet
    ? raw
    : triggerRaw;

const contextPacketInput = parseJson(source.context_packet, {});

const event = parseJson(source.event, {});
const lead = parseJson(source.lead, {});
const leadStateInput = parseJson(source.lead_state, {});
const memory = parseJson(source.memory, {});
const businessRules = parseJson(source.business_rules, {});
const ruleResult = parseJson(source.rule_result, {});
const decision = parseJson(source.decision, {});
const route = parseJson(source.route, {});
const meta = parseJson(source.meta, {});

const leadId = firstValue(
  lead.id,
  lead.lead_id,
  leadStateInput.lead_id,
  contextPacketInput.lead?.id,
  contextPacketInput.state?.lead_id
);

const phone = firstValue(
  lead.phone,
  lead.external_id,
  contextPacketInput.lead?.phone,
  contextPacketInput.lead?.external_id
);

const channel = firstValue(
  lead.channel,
  event.channel,
  contextPacketInput.lead?.channel,
  "whatsapp"
);

if (!leadId) {
  throw new Error("context_builder missing lead_id");
}

if (!phone) {
  throw new Error("context_builder missing phone");
}

const missingFields = cleanArray(
  ruleResult.missing_fields?.length
    ? ruleResult.missing_fields
    : leadStateInput.missing_fields
);

const state = compactObject({
  ...leadStateInput,

  lead_id: leadStateInput.lead_id || leadId,
  stage: safeString(leadStateInput.stage, "new_lead"),
  intent_last: safeString(leadStateInput.intent_last),
  interest_score: safeNumber(leadStateInput.interest_score, 0),
  next_goal: safeString(leadStateInput.next_goal, "identify_intent"),

  service_interest: safeString(leadStateInput.service_interest),
  service_scope: safeString(leadStateInput.service_scope),
 vehicle_type: safeString(
  leadStateInput.confirmed_vehicle_type || leadStateInput.vehicle_type
),

district: safeString(
  leadStateInput.confirmed_district || leadStateInput.district
),

mentioned_vehicle_type: safeString(leadStateInput.mentioned_vehicle_type),
confirmed_vehicle_type: safeString(
  leadStateInput.confirmed_vehicle_type || leadStateInput.vehicle_type
),

mentioned_district: safeString(leadStateInput.mentioned_district),
confirmed_district: safeString(
  leadStateInput.confirmed_district || leadStateInput.district
),
  missing_fields: missingFields,
  last_bot_action: safeString(leadStateInput.last_bot_action),
  human_handoff: leadStateInput.human_handoff === true,

  booking_options: Array.isArray(leadStateInput.booking_options)
    ? leadStateInput.booking_options
    : parseJson(leadStateInput.booking_options, []),

  booking_date: safeString(leadStateInput.booking_date),
  booking_time: safeString(leadStateInput.booking_time),
  slot_id: safeString(leadStateInput.slot_id),

  availability_confirmed:
    leadStateInput.availability_confirmed === true
      ? true
      : leadStateInput.availability_confirmed === false
        ? false
        : null,

  availability_window: safeString(leadStateInput.availability_window),
  availability_label: safeString(leadStateInput.availability_label),
  days_ahead: safeNumber(leadStateInput.days_ahead),
  start_offset_days: safeNumber(leadStateInput.start_offset_days),
  max_slots: safeNumber(leadStateInput.max_slots),
  duration_minutes: safeNumber(leadStateInput.duration_minutes, 120),
  calendar_id: safeString(leadStateInput.calendar_id),

  service_address: safeString(leadStateInput.service_address),
  address: safeString(leadStateInput.address),
  address_reference: safeString(leadStateInput.address_reference),

  address_confirmed:
    leadStateInput.address_confirmed === true
      ? true
      : leadStateInput.address_confirmed === false
        ? false
        : null,

  followup_type: safeString(leadStateInput.followup_type),
  scheduled_for: safeString(leadStateInput.scheduled_for),
});

const stage = state.stage || "new_lead";

const hasService = !!state.service_interest;
const hasDistrict = !!state.district;
const hasVehicle = !!state.vehicle_type;

const hasBookingDate = !!state.booking_date;
const hasBookingTime = !!state.booking_time;
const hasSlot = !!state.slot_id || (hasBookingDate && hasBookingTime);

const hasBookingOptions =
  Array.isArray(state.booking_options) && state.booking_options.length > 0;

const hasBookingCandidate = hasSlot || hasBookingOptions;

const hasAddress = !!(
  state.service_address ||
  state.address ||
  state.address_reference ||
  state.address_confirmed === true
);

const activeAppointment = memory.last_appointment || null;

const hasActiveAppointment = !!(
  activeAppointment &&
  ["confirmed", "pending", "booked"].includes(
    String(activeAppointment.status || "").toLowerCase()
  )
);

const isHandoffLocked =
  state.human_handoff === true || stage === "human_handoff";

const SUPPORTED_ACTIONS = [
  "ask_missing_data",
  "send_quote",
  "answer_question",
  "answer_objection",
  "offer_booking",
  "offer_available_slots",
  "confirm_booking",
  "schedule_followup",
  "handoff_human",

  "cancel_booking",
  "reschedule_booking",
  "collect_address",
  "confirm_address",
  "send_pre_service_instructions",
  "notify_on_the_way",
  "request_review",
  "request_referral",
  "send_service_menu",
  "recommend_service",
];

const UNSUPPORTED_PRODUCT_ACTIONS_PENDING = [
];

const ALLOWED_ACTIONS_BY_STAGE = {
new_lead: [
  "send_service_menu",
  "recommend_service",
  "ask_missing_data",
  "answer_question",
  "send_quote",
  "offer_available_slots",
  "handoff_human",
],

service_discovery: [
  "send_service_menu",
  "recommend_service",
  "ask_missing_data",
  "send_quote",
  "offer_available_slots",
  "answer_question",
  "handoff_human",
],

qualified: [
  "send_service_menu",
  "recommend_service",
  "send_quote",
  "offer_available_slots",
  "answer_question",
  "answer_objection",
  "offer_booking",
  "handoff_human",
],

quoted: [
  "answer_objection",
  "offer_available_slots",
  "collect_address",
  "answer_question",
  "offer_booking",
  "handoff_human",
],

objection: [
  "answer_objection",
  "offer_available_slots",
  "answer_question",
  "offer_booking",
  "handoff_human",
],

closing: [
  "offer_available_slots",
  "collect_address",
  "answer_question",
  "answer_objection",
  "offer_booking",
  "handoff_human",
],

booking_selection: [
  "confirm_booking",
  "collect_address",
  "offer_available_slots",
  "reschedule_booking",
  "answer_question",
  "handoff_human",
],

collecting_address: [
  "confirm_address",
  "collect_address",
  "answer_question",
  "handoff_human",
],

address_confirmation: [
  "confirm_address",
  "confirm_booking",
  "collect_address",
  "answer_question",
  "handoff_human",
],

  booked: [
    "cancel_booking",
    "reschedule_booking",
    "send_pre_service_instructions",
    "notify_on_the_way",
    "answer_question",
    "handoff_human",
  ],

  cancelling: [
    "cancel_booking",
    "answer_question",
    "handoff_human",
  ],

  reschedule: [
    "reschedule_booking",
    "offer_available_slots",
    "answer_question",
    "handoff_human",
  ],

  post_service: [
    "request_review",
    "request_referral",
    "answer_question",
    "handoff_human",
  ],

  reactivation: [
    "send_quote",
    "offer_available_slots",
    "answer_question",
    "schedule_followup",
    "handoff_human",
  ],

  lost: [
    "schedule_followup",
    "handoff_human",
  ],

  human_handoff: [],
};

function actionRequirements(action) {
  const map = {
    ask_missing_data: [],
    send_service_menu: [],
    recommend_service: [],
    answer_question: [],
    answer_objection: [],
    offer_booking: ["service_interest"],

    send_quote: [
      "service_interest",
      "vehicle_type",
      "district",
    ],

    offer_available_slots: [
      "service_interest",
      "vehicle_type",
      "district",
    ],

    confirm_booking: [
      "service_interest",
      "vehicle_type",
      "district",
      "booking_date",
      "booking_time",
      "address",
    ],

    collect_address: ["booking_candidate"],
    confirm_address: ["address_candidate"],

    cancel_booking: [],
    reschedule_booking: [],

    send_pre_service_instructions: [],
    notify_on_the_way: [],

    request_review: [],
    request_referral: [],

    schedule_followup: [
      "followup_type",
      "scheduled_for",
    ],

    handoff_human: [],
  };

  return map[action] || [];
}

function missingForAction(action) {
  return actionRequirements(action).filter((field) => {
    if (field === "service_interest") return !hasService;
    if (field === "vehicle_type") return !hasVehicle;
    if (field === "district") return !hasDistrict;

    if (field === "booking_date") return !hasBookingDate;
    if (field === "booking_time") return !hasBookingTime;

    if (field === "address") return !hasAddress;
    if (field === "booking_candidate") return !hasBookingCandidate;

    if (field === "address_candidate") {
      return !hasAddress && !safeString(event.text);
    }

    if (field === "followup_type") return !state.followup_type;
    if (field === "scheduled_for") return !state.scheduled_for;

    return false;
  });
}

function canRunAction(action) {
  if (!SUPPORTED_ACTIONS.includes(action)) return false;
  if (isHandoffLocked) return false;

  // Servicio a domicilio:
  // nunca confirmar reserva sin dirección.
  if (action === "confirm_booking" && !hasAddress) {
    return false;
  }

  if (["send_quote", "offer_available_slots"].includes(action)) {
    return hasService && hasVehicle && hasDistrict;
  }

  if (action === "confirm_booking") {
    return (
      hasService &&
      hasVehicle &&
      hasDistrict &&
      hasBookingDate &&
      hasBookingTime &&
      hasAddress
    );
  }

  if (action === "collect_address") {
    return (
      hasBookingCandidate ||
      [
        "quoted",
        "closing",
        "booking_selection",
        "booking_confirmation",
      ].includes(stage)
    );
  }

  if (action === "confirm_address") {
    return (
      hasAddress ||
      [
        "collecting_address",
        "address_confirmation",
      ].includes(stage)
    );
  }

  if (["cancel_booking", "reschedule_booking"].includes(action)) {
  return true;
}

  if (
    [
      "send_pre_service_instructions",
      "notify_on_the_way",
    ].includes(action)
  ) {
    return hasActiveAppointment || stage === "booked";
  }

 if (["request_review", "request_referral"].includes(action)) {
  const ruleAction = safeString(ruleResult.action);

  return (
    stage === "post_service" ||
    ruleAction === "request_review" ||
    ruleAction === "request_referral"
  );
}

  if (action === "schedule_followup") {
    return !!state.followup_type && !!state.scheduled_for;
  }

  return true;
}

function buildAllowedActions() {
  if (isHandoffLocked) return [];

  const ruleAction = safeString(ruleResult.action);

  // Si rules_engine ya resolvió una acción dura,
  // context_builder deja pasar solo esa acción.
  if (ruleAction) {
    if (SUPPORTED_ACTIONS.includes(ruleAction)) {
      return [ruleAction];
    }

    return [];
  }

  let candidates =
    ALLOWED_ACTIONS_BY_STAGE[stage] ||
    ALLOWED_ACTIONS_BY_STAGE.new_lead;

  // Si faltan campos críticos, se prioriza pedir datos.
   if (missingFields.length > 0) {
    candidates = [
      "send_service_menu",
      "recommend_service",
      "ask_missing_data",
      "answer_question",
      "handoff_human",
    ];
  }

  // Si ya tiene los datos comerciales básicos,
  // habilitamos cotización y disponibilidad aunque el stage venga atrasado.
if (hasService && hasVehicle && hasDistrict) {
  candidates = unique(candidates)
    .filter((action) => action !== "recommend_service");

  if (!["quoted", "closing", "booking_selection", "booking_confirmation", "collecting_address", "address_confirmation", "booked"].includes(stage)) {
    candidates.unshift("send_quote");
  }

  candidates.push("offer_available_slots", "answer_question", "offer_booking");
}

  // Si hay fecha/hora elegida pero falta dirección:
  // bloqueamos confirm_booking y priorizamos collect_address.
if (hasBookingDate && hasBookingTime && !hasAddress) {
  if (state.availability_confirmed === true) {
    candidates = [
      "collect_address",
      "answer_question",
      "handoff_human",
    ];
  } else {
    candidates = [
      "offer_available_slots",
      "answer_question",
      "handoff_human",
    ];
  }
}

  // Si hay fecha/hora + dirección:
  // sí se puede confirmar reserva.
  if (
    hasService &&
    hasVehicle &&
    hasDistrict &&
    hasBookingDate &&
    hasBookingTime &&
    hasAddress
  ) {
    candidates.unshift("confirm_booking");
  }

  // Si ya hay cita activa o stage booked,
  // habilitamos acciones operativas.
  if (hasActiveAppointment || stage === "booked") {
    candidates.push(
      "cancel_booking",
      "reschedule_booking",
      "send_pre_service_instructions",
      "notify_on_the_way"
    );
  }

  candidates = unique(candidates)
    .filter((action) => SUPPORTED_ACTIONS.includes(action))
    .filter((action) => canRunAction(action));

  if (!candidates.includes("handoff_human")) {
    candidates.push("handoff_human");
  }

  return unique(candidates);
}

function normalizeForIntent(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function userWantsCancel(rawText) {
  const t = normalizeForIntent(rawText);

  return (
    t.includes("cancelar") ||
    t.includes("cancela") ||
    t.includes("cancelame") ||
    t.includes("anular") ||
    t.includes("anula") ||
    t.includes("no voy a poder") ||
    t.includes("no podre") ||
    t.includes("no puedo asistir") ||
    t.includes("no puedo ir")
  );
}

function userWantsReschedule(rawText) {
  const t = normalizeForIntent(rawText);

  return (
    t.includes("reagendar") ||
    t.includes("reprogramar") ||
    t.includes("cambiar la hora") ||
    t.includes("cambiar hora") ||
    t.includes("cambiar fecha") ||
    t.includes("mover la hora") ||
    t.includes("otra hora") ||
    t.includes("otro horario") ||
    t.includes("otro dia") ||
    t.includes("otro día")
  );
}

let allowedActions = buildAllowedActions();

const currentTextForPriority = safeString(event.text, "");

if (userWantsCancel(currentTextForPriority)) {
  allowedActions = unique([
    "cancel_booking",
    ...allowedActions.filter((action) => action !== "cancel_booking")
  ]);
}

if (userWantsReschedule(currentTextForPriority)) {
  allowedActions = unique([
    "reschedule_booking",
    ...allowedActions.filter((action) => action !== "reschedule_booking")
  ]);
}

const latestUserMessage = safeString(event.text, "");

const shortSummary = firstValue(
  memory.short_summary,
  contextPacketInput.conversation?.short_summary,
  latestUserMessage,
  ""
);

const contextPacket = {
  lead: {
    id: leadId,
    name: safeString(lead.name, "Cliente"),
    phone,
    channel,
    external_id: firstValue(lead.external_id, phone),
  },

  state,

conversation: {
  message_type: safeString(event.message_type, "text"),
  latest_user_message: latestUserMessage,
  short_summary: shortSummary,
  last_message_id: safeString(event.message_id),
  chat_session_id: event.source_metadata?.chat_session_id || null,
},

source_metadata: {
  ...(event.source_metadata || {})
},

  business: {
    services: Array.isArray(businessRules.services)
      ? businessRules.services
      : [],

    pricing_policy: safeString(
      businessRules.pricing_policy,
      ""
    ),

    district_policy: safeString(
      businessRules.district_policy,
      ""
    ),

    booking_policy: safeString(
      businessRules.booking_policy,
      ""
    ),

    currency: safeString(
      businessRules.currency,
      "CLP"
    ),
  },

  rule_context: {
    rule_result: {
      resolution_type: safeString(
        ruleResult.resolution_type,
        "send_to_llm"
      ),

      action: safeString(ruleResult.action),
      reason: safeString(ruleResult.reason),
      message: ruleResult.message ?? null,

      missing_fields: cleanArray(ruleResult.missing_fields),

      should_call_llm: ruleResult.should_call_llm === true,

      state_update: ruleResult.state_update || {},

      rule_name: safeString(ruleResult.rule_name),
      priority: safeNumber(ruleResult.priority),
    },

    decision_from_rules: decision || null,
    route: route || {},
  },

  context_hints: {
    has_missing_fields: missingFields.length > 0,
    missing_fields_count: missingFields.length,
    priority_missing_fields: missingFields,

    has_service: hasService,
    has_vehicle: hasVehicle,
    has_district: hasDistrict,

    has_booking_candidate: hasBookingCandidate,
    has_booking_options: hasBookingOptions,

    has_address: hasAddress,

    has_active_appointment: hasActiveAppointment,

    is_handoff_locked: isHandoffLocked,

    latest_message_present: !!latestUserMessage,
    has_short_summary: !!memory.short_summary,

    stage_goal: {
      service_discovery: "identify_service_then_collect_vehicle_and_district",
      new_lead: "qualify_lead",
      qualified: "quote_or_offer_slots",
      quoted: "move_to_booking",
      objection: "handle_objection_then_book",
      closing: "book_appointment",
      booking_selection: "collect_slot_or_address",
      booking_confirmation: "confirm_booking_after_address",
      collecting_address: "collect_and_validate_address",
      address_confirmation: "validate_address_then_confirm_booking",
      booked: "manage_existing_booking",
      post_service: "review_and_referral",
      human_handoff: "human_takeover",
    }[stage] || "continue_conversation",

    action_requirements_missing: Object.fromEntries(
      allowedActions.map((action) => [
        action,
        missingForAction(action),
      ])
    ),

    unsupported_product_actions_pending:
      UNSUPPORTED_PRODUCT_ACTIONS_PENDING,
  },

  commercial_memory: {
    commercial_flags: Array.isArray(memory.commercial_flags)
      ? memory.commercial_flags
      : [],

    last_quote: memory.last_quote || null,
    last_appointment: memory.last_appointment || null,
  },

  allowed_actions: cleanArray(allowedActions),
};

return [
  {
    json: {
      context_packet: contextPacket,
      meta: {
        ...meta,
        source: "context_builder",
        context_builder_version: "2.0.0",
        allowed_actions_strategy:
          "stage_machine_with_data_filters",
      },
    },
  },
];

const input = $json || {};
const contextPacket = input.context_packet || {};

const lead = contextPacket.lead || {};
const state = contextPacket.state || {};
const conversation = contextPacket.conversation || {};
const business = contextPacket.business || {};
const ruleContext = contextPacket.rule_context || {};
const contextHints = contextPacket.context_hints || {};

const leadId =
  lead.id ||
  state.lead_id ||
  null;

const phone =
  lead.phone ||
  lead.external_id ||
  null;

const channel =
  lead.channel ||
  input.channel ||
  "whatsapp";

const errors = [];

if (!leadId) {
  errors.push("context_packet.lead.id missing");
}

if (!phone) {
  errors.push("context_packet.lead.phone missing");
}

if (!channel) {
  errors.push("context_packet.lead.channel missing");
}

if (!contextPacket.state || typeof contextPacket.state !== "object") {
  errors.push("context_packet.state missing");
}

if (!contextPacket.conversation || typeof contextPacket.conversation !== "object") {
  errors.push("context_packet.conversation missing");
}

if (!Array.isArray(contextPacket.allowed_actions)) {
  errors.push("context_packet.allowed_actions must be array");
}

if (errors.length > 0) {
  throw new Error(errors.join(" | "));
}

return [
  {
    json: {
      ...input,
      context_packet: {
        ...contextPacket,

        lead: {
          ...lead,
          id: leadId,
          phone,
          channel,
          external_id: lead.external_id || phone,
          name: lead.name || "Cliente"
        },

        state: {
          ...state,
          lead_id: state.lead_id || leadId,
          missing_fields: Array.isArray(state.missing_fields)
            ? state.missing_fields
            : []
        },

        conversation: {
          message_type: conversation.message_type || "text",
          latest_user_message: conversation.latest_user_message || "",
          short_summary: conversation.short_summary || "",
          last_message_id: conversation.last_message_id || null
        },

        business,

        rule_context: ruleContext,

        context_hints: contextHints,

        allowed_actions: contextPacket.allowed_actions
      },

      validation: {
        context_packet_valid: true,
        validated_at: new Date().toISOString()
      }
    }
  }
];

const input = $json || {};

const contextPacket = input.context_packet || null;

if (!contextPacket || typeof contextPacket !== "object") {
  throw new Error("Missing context_packet in context_builder output");
}

if (!contextPacket.lead || typeof contextPacket.lead !== "object") {
  throw new Error("Missing context_packet.lead");
}

if (!contextPacket.lead.id) {
  throw new Error("Missing context_packet.lead.id");
}

if (!contextPacket.lead.phone) {
  throw new Error("Missing context_packet.lead.phone");
}

if (!contextPacket.lead.channel) {
  contextPacket.lead.channel = "whatsapp";
}

if (!contextPacket.state || typeof contextPacket.state !== "object") {
  throw new Error("Missing context_packet.state");
}

if (!contextPacket.state.lead_id) {
  contextPacket.state.lead_id = contextPacket.lead.id;
}

if (!Array.isArray(contextPacket.state.missing_fields)) {
  contextPacket.state.missing_fields = [];
}

if (!contextPacket.conversation || typeof contextPacket.conversation !== "object") {
  contextPacket.conversation = {};
}

contextPacket.conversation.message_type =
  contextPacket.conversation.message_type || "text";

contextPacket.conversation.latest_user_message =
  contextPacket.conversation.latest_user_message || "";

contextPacket.conversation.short_summary =
